def run():
    industry_commit_link = [commit_link for commit_link in build.params_id.commit_link_ids if commit_link.commit_id.repo_id.project_id.name=="Industry"][0]
    bundle = build.params_id.create_batch_id.bundle_id
    all_industry_modules = set(m.split('/')[0] for m in industry_commit_link.commit_id._list_files([f':(glob)*/*']) if m and not '.' in m.split('/')[0]) - {'tests'}

    modules_to_test = all_industry_modules
    industry_commit = industry_commit_link.commit_id

    if industry_commit_link.merge_base_commit_id and not bundle.sticky:
        modified = industry_commit.repo_id._git(['diff', '--name-only', '%s..%s' % (industry_commit_link.merge_base_commit_id.name, industry_commit.name)])
        modified_directory = set()
        if modified:
            for file in modified.split('\n'):
                file = file.strip().strip('"')
                if file:
                    directory = file.split('/')[0]
                    if '.' in directory:
                        continue
                    if directory == 'tests':
                        test_dir = file.split('/')[1].removeprefix('test_')
                        if test_dir in all_industry_modules:
                            directory = test_dir
                    modified_directory.add(directory)
            if 'tests' not in modified_directory:
                modules_to_test = modified_directory

    modules_to_test = modules_to_test - {'.tx'}

    docker_params = self._run_install_odoo(build)
    docker_params['cmd'].cmd.clear()

    base_cmd = [
        'odoo/odoo-bin', 'test_industry',
        '-d', build.dest,
        '--data-dir', '/data/build/datadir/',
        '--test-enable',
        '--log-db', 'runbot_logs',
        '--log-db-level=26',
        '--industry-demo'
    ]

    if modules_to_test == all_industry_modules or not modules_to_test:
        build._log('run', 'Running ALL industries')
        base_cmd.append('--all')
    else:
        industries_list = ','.join(sorted(modules_to_test))
        build._log('run', f'Smart testing triggered for: {industries_list}')
        base_cmd.extend(['--industries', industries_list])

    [docker_params['cmd'].cmd.append(arg) for arg in base_cmd]
    return docker_params
